const final = {};
let mensagens = [];

for (const item of items) {
  const json = item.json;
  if (json.Mensagem) mensagens.push(json.Mensagem);
  for (const key in json) {
    if (key !== 'Mensagem') final[key] = json[key];
  }
  // Meta WABA: From ja vem como numero limpo (ex: 5571993643490)
  if (json.From && !final.telefone) {
    final.telefone = json.From;
  }
}

final.Mensagem = mensagens.join('\n');
return [{ json: final }];

// Code2 v4
var texto = $('Orquestrador').first().json.output;
if (!texto || texto.trim().toUpperCase() === 'STOP') return [];
var t = texto.trim().toUpperCase();
if (t === 'AGENTE' || t === 'BOT' || t === 'HUMANO') return [];
if (!texto.trim()) return [];
var mensajes = texto.split(/\n+/).map(function(p){return p.trim()}).filter(function(p){return p.length > 0});
return mensajes.map(function(m){ return {json:{text:m}} });

